2	
3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_SURCHARGE = 0.1;
5	
6	const BASE_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	
13	type Item = { type: string };
14	type Step = { op: string; items: Item[] };
15	type Scenario = { steps: Step[] };
16	
17	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
18	
19	const sumItemBasePremiums = (items: Item[]): number =>
20	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
21	
22	export function runScenario(scenario: unknown): { results: { premium: number }[] } {
23	  const step = (scenario as Scenario).steps[0];
24	  const itemsBase = sumItemBasePremiums(step.items);
25	  const policyBase = itemsBase + itemsBase * FIRST_INSURANCE_SURCHARGE;
26	  const premium = policyBase + PROCESSING_FEE;
27	  return { results: [{ premium }] };
28	}
